// Sunset header in HTTP response
HTTP/1.1 200 OK
Content-Type: application/json
Sunset: Sat, 01 Nov 2026 23:59:59 GMT
Link: <https://api.example.com/migration/v1-to-v2>; rel="migration"

// API deprecation in OpenAPI 3.x
{
  "openapi": "3.0.0",
  "info": {
    "title": "Order Service",
    "version": "1.2.0",
    "description": "**DEPRECATED** Use v2 instead. Sunset: 2026-11-01"
  }
}

HTTP/1.1 422 Unprocessable Entity
Content-Type: application/problem+json

{
  "type": "https://api.example.com/errors/order-validation",
  "title": "Order Validation Failed",
  "status": 422,
  "detail": "The order could not be created due to validation errors.",
  "instance": "/v1/orders",
  "errors": [
    {
      "field": "customer.email",
      "message": "Email address is already associated with a different customer.",
      "code": "DUPLICATE_EMAIL"
    },
    {
      "field": "order.items[0].quantity",
      "message": "Requested quantity (100) exceeds available stock (42).",
      "code": "INSUFFICIENT_STOCK"
    }
  ]
}
